kernel_src = """
#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelLogSoftmaxCustom {
public:
    __aicore__ inline KernelLogSoftmaxCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t rowLength,
                                uint32_t blockDim, int32_t dim)
    {
        totalLen_ = totalLength;
        rowLen_ = rowLength;
        blockDim_ = blockDim;
        dim_ = dim;
        numRows_ = totalLen_ / rowLen_;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, rowLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, rowLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, 1, rowLen_ * sizeof(float)); // only for exp
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || rowLen_ == 0) return;

        uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());
        uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());

        for (uint32_t row = blockIdx; row < numRows_; row += blockNum)
        {
            uint32_t rowOffset = row * rowLen_;
            LogSoftmaxRow(rowOffset);
        }
    }

private:
    __aicore__ inline void LogSoftmaxRow(uint32_t rowOffset)
    {
        AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
        AscendC::DataCopy(xLocal, xGm_[rowOffset], rowLen_);

        float rowMax;
        AscendC::ReduceMax(rowMax, xLocal, rowLen_);

        AscendC::LocalTensor<float> expLocal = tmpQueue_.AllocTensor<float>();
        AscendC::Sub(expLocal, xLocal, rowMax, rowLen_);
        AscendC::Exp(expLocal, expLocal, rowLen_);

        float rowSum;
        AscendC::ReduceSum(rowSum, expLocal, rowLen_);

        float logSum = logf(rowSum);

        AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();
        AscendC::Sub(yLocal, xLocal, rowMax, rowLen_);
        AscendC::Sub(yLocal, yLocal, logSum, rowLen_);

        AscendC::DataCopy(yGm_[rowOffset], yLocal, rowLen_);

        outQueueY_.FreeTensor(yLocal);
        tmpQueue_.FreeTensor(expLocal);
        inQueueX_.FreeTensor(xLocal);
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalLen_ {0};
    uint32_t rowLen_ {0};
    uint32_t blockDim_ {0};
    uint32_t numRows_ {0};
    int32_t dim_ {1};
};

extern "C" __global__ __aicore__ void log_softmax_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelLogSoftmaxCustom op;
    op.Init(x, y, tiling_data.totalLength, tiling_data.rowLength, tiling_data.blockDim, tiling_data.dim);
    op.Process();
}
